--
-- Table structure for table `contest_questions`
--

DROP TABLE IF EXISTS `contest_questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contest_questions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `contest_id` bigint unsigned NOT NULL,
  `explanation_type` enum('text','video','image','audio','none') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text',
  `time_limit` int NOT NULL DEFAULT '0',
  `order` int NOT NULL DEFAULT '1',
  `is_display_split_tab` tinyint(1) NOT NULL DEFAULT '1',
  `question_type` enum('multiple_choice','single_choice','true_false','fill_in_the_blank','multiple_dropdown','draggable_rearrange','multi_column_single_choice','multi_column_multi_choice','drag_drop_matching') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'multiple_choice',
  `question_input_type` enum('text','multi_tab_based','single_tab_based','video','image','audio') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text',
  `options` longtext COLLATE utf8mb4_unicode_ci,
  `correct_answers` longtext COLLATE utf8mb4_unicode_ci,
  `score` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `question_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `contest_questions_contest_id_foreign` (`contest_id`),
  KEY `contest_questions_question_id_foreign` (`question_id`),
  CONSTRAINT `contest_questions_contest_id_foreign` FOREIGN KEY (`contest_id`) REFERENCES `contests` (`id`) ON DELETE CASCADE,
  CONSTRAINT `contest_questions_question_id_foreign` FOREIGN KEY (`question_id`) REFERENCES `questions` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=481 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

