CREATE TABLE `contest_winners` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `contest_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `participant_id` bigint unsigned DEFAULT NULL,
  `prize_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `prize_amount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `rank` int NOT NULL DEFAULT '0' COMMENT 'Rank of the winner in the contest, e.g., 1 for first place, 2 for second place, etc.',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `contest_winners_contest_id_foreign` (`contest_id`),
  KEY `contest_winners_user_id_foreign` (`user_id`),
  KEY `contest_winners_participant_id_foreign` (`participant_id`),
  CONSTRAINT `contest_winners_contest_id_foreign` FOREIGN KEY (`contest_id`) REFERENCES `contests` (`id`) ON DELETE CASCADE,
  CONSTRAINT `contest_winners_participant_id_foreign` FOREIGN KEY (`participant_id`) REFERENCES `contest_participants` (`id`) ON DELETE SET NULL,
  CONSTRAINT `contest_winners_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
