INSERT INTO `faqs` VALUES (1,'What is a quizix?','Chartering a quizix provides a unique, luxurious, and customizable travel experience, offering privacy and access to exclusive destinations.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(2,'Can you pick us up from our location?','Yes, we provide pick-up services from our location.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(3,'What is your cancellation policy?','We have a flexible cancellation policy. If you need to cancel your reservation, please contact us within 24 hours of your booking date.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(4,'What is your refund policy?','We have a refund policy. If you need to cancel your reservation, please contact us within 24 hours of your booking date.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(5,'What is your privacy policy?','We have a privacy policy. If you need to cancel your reservation, please contact us within 24 hours of your booking date.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(6,'What type of quizix should you choose?','Consider preferences, group size, and the desired experience. Factors such as speed, comfort, and on-board amenities guide the choice between motor quizixs, sailing quizixs, or catamarans.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(7,'How do I book a quizix?','To book a quizix, simply visit our website and select the desired quizix, dates, and preferences. You can also contact us for more information.','2026-04-04 06:13:33','2026-04-04 06:13:33'),(8,'What is your cancellation policy?','We have a flexible cancellation policy. If you need to cancel your reservation, please contact us within 24 hours of your booking date.','2026-04-04 06:13:33','2026-04-04 06:13:33');
/*!40000 ALTER TABLE `faqs` ENABLE KEYS */;
UNLOCK TABLES;

