INSERT INTO `frontend_sections` VALUES (1,'Articles Hero','ph ph-newspaper','articles-hero','Hero banner for the articles list page. Supports title, subtitle, description, background image, and optional CTA button.','{\"title\":\"Blog & Articles\",\"subtitle\":\"Stories, Insights & Updates\",\"description\":\"Stay informed with the latest tips, updates, and insights from our community.\",\"image\":\"\",\"button\":{\"text\":\"\",\"link\":\"\\/articles\"}}'),(2,'Article List','ph ph-list-bullets','article-list','Renders the full article list with search, category filters, tag filters, and pagination. No editable content — fully dynamic.','[]'),(3,'Latest Articles','ph ph-article','latest-articles','Showing latest articles with title and description.','{\"title\":\"Latest Articles\",\"description\":\"Stay informed with the latest tips, updates, and insights from our community.\",\"button\":{\"text\":\"View All Articles\",\"link\":\"\\/articles\"},\"limit\":3}'),(4,'Home Hero','ph ph-house','home-hero','This is home hero section','{\"image\":\"\\/assets\\/client\\/illustration\\/hero-img.png\",\"title\":\"Test Your Knowledge\",\"text-slider\":[\"Math Quiz\",\"Science Quiz\",\"History Quiz\",\"Tech Quiz\",\"Physics Quiz\",\"Biology Quiz\"],\"button\":{\"text\":\"Get Started\",\"link\":\"\\/quizzes\"}}'),(5,'Custom Ads','ph ph-alien','custom-ads','This is custom ads section','[]'),(6,'How It Works','ph ph-house','how-it-works','This is home hero section','{\"title\":\"How It Works\",\"description\":\"Create an account, explore quizzes, test your knowledge, and track your progress effortlessly.\",\"steps\":[{\"image\":\"\\/assets\\/client\\/illustration\\/how-it-woks-illus-1.png\",\"title\":\"Sign Up\",\"description\":\"Sign up easily and securely to start your quiz journey.\"},{\"image\":\"\\/assets\\/client\\/illustration\\/how-it-woks-illus-2.png\",\"title\":\"Choose A Quiz\",\"description\":\"Explore and choose from a wide range of exciting and diverse categories available for you.\"},{\"image\":\"\\/assets\\/client\\/illustration\\/how-it-woks-illus-3.png\",\"title\":\"Check Your Score\",\"description\":\"Test your knowledge and see how you rank. Check your score now and improve!\"}]}'),(7,'Testimonials','ph ph-phone','testimonials','Showing some testimonials with title and description.','{\"title\":\"What Our Users Say\",\"sub_title\":\"Testimonials\",\"description\":\"Discover why users love our quizzes. Fun, educational, and completely engaging.\",\"limit\":6}'),(8,'Top Players','ph ph-phone','top-players','Showing some top players with title and description.','{\"title\":\"Top Player\",\"description\":\"Create an account, explore quizzes, test your knowledge, and track your progress effortlessly.\",\"button\":{\"text\":\"View All\",\"link\":\"\\/top-players\"},\"limit\":4}'),(9,'Upcoming Contests','ph ph-book','upcoming-contests','Showing some upcoming contests with title and description.','{\"title\":\"\",\"description\":\"Create an account, explore quizzes, test your knowledge, and track your progress effortlessly.\",\"button\":{\"text\":\"View All\",\"link\":\"\\/contests\"},\"limit\":3}'),(10,'Subscribe Section','ph ph-address-book','subscribe-section','Showing some subscribe section with title and description.','{\"title\":\"Subscribe For The Daily Updates\",\"description\":\"Discover why users love our quizzes. Fun, educational, and completely engaging\"}'),(11,'Footer','ph ph-bathtub','footer','Showing some footer with title and description.','{\"quick_links\":{\"title\":\"Quick Links\",\"is_show\":1},\"resources\":{\"title\":\"Resources\",\"is_show\":1},\"Contact\":{\"title\":\"Contact\",\"is_show\":1},\"social_links\":{\"is_show\":1}}'),(12,'Three Quizzes','ph ph-book','three-quizzes','Showing some upcoming quizzes with title and description.','{\"description\":\"Create an account, explore quizzes, test your knowledge, and track your progress effortlessly.\",\"button\":{\"text\":\"View All\",\"link\":\"\\/quizzes\"},\"limit\":3}'),(13,'Counter Section','ph ph-phone','counter-section','Showing some top players with title and description.','{\"list\":[{\"title\":\"Active Players\",\"value\":\"20\",\"unit\":\"k+\"},{\"title\":\"Contest Completed\",\"value\":\"50\",\"unit\":\"k+\"},{\"title\":\"Total Questions\",\"value\":\"100\",\"unit\":\"k+\"},{\"title\":\"Categories Covered\",\"value\":\"20\",\"unit\":\"+\"}]}'),(14,'FAQ','ph ph-phone','faq-section','Showing some faq with questions and answers.','{\"title\":\"Frequently Asked Questions\",\"description\":\"Discover why users love our quizzes. Fun, educational, and completely engaging experiences that challenge your knowledge and keep you coming back for more.\",\"limit\":6,\"image\":\"\\/assets\\/client\\/illustration\\/faq-illus.png\",\"faqs\":[{\"question\":\"What types of quizzes are available?\",\"answer\":\"We offer a wide range of quizzes across various categories including science, history, pop culture, and more.\"},{\"question\":\"How do I create an account?\",\"answer\":\"You can create an account by clicking on the \\\"Register\\\" button and filling out the required information.\"},{\"question\":\"Can I track my progress?\",\"answer\":\"Yes, you can track your quiz scores and progress through your user dashboard.\"},{\"question\":\"Is there a mobile app available?\",\"answer\":\"Currently, we do not have a mobile app, but our website is fully responsive and works well on mobile devices.\"},{\"question\":\"How can I contact support?\",\"answer\":\"You can contact our support team via the contact form on our website or through our email support.\"}]}'),(15,'Unique Quiz Features','ph ph-info','unique-quiz-features','This is quiz feature section. In this section you can add your quiz features.','{\"title\":\"Unique Quiz Features\",\"description\":\"Explore unique quiz features designed to challenge, entertain, and educate. Dive into interactive quizzes and enhance your knowledge effortlessly.\",\"image\":\"\\/assets\\/client\\/illustration\\/unique-quiz-feature-img.png\",\"features\":[{\"image\":\"\\/assets\\/client\\/illustration\\/quiz-feature-icon-1.png\",\"title\":\"Timed Challenges\",\"description\":\"Race against the clock to complete quizzes and add excitement to your learning.\"},{\"image\":\"\\/assets\\/client\\/illustration\\/quiz-feature-icon-2.png\",\"title\":\"Multi-Topic Quizzes\",\"description\":\"Explore diverse topics from science to pop culture, tailored for curious minds.\"},{\"image\":\"\\/assets\\/client\\/illustration\\/quiz-feature-icon-3.png\",\"title\":\"Team Quizzes\",\"description\":\"Join forces with friends or colleagues and tackle quizzes together for team fun.\"},{\"image\":\"\\/assets\\/client\\/illustration\\/quiz-feature-icon-4.png\",\"title\":\"Brain Teasers\",\"description\":\"Challenge yourself with puzzles and riddles that keep your mind sharp.\"}]}'),(16,'The Journey','ph ph-house','the-journey','This is the journey section.','{\"image\":\"\\/assets\\/client\\/illustration\\/hero-img.png\",\"title\":\"The Journey Behind Our Quizzes\",\"description\":\"we\\u2019re dedicated revolutionizing the way the world uses energy. mission is to provide reliable, affordable\",\"tab-data\":[{\"title\":\"Our Mission\",\"description\":\"Our mission is to create engaging quizzes that challenge and entertain users while promoting knowledge sharing.\"},{\"title\":\"Our Vision\",\"description\":\"We envision a world where learning is fun, accessible, and interactive through innovative quiz experiences.\"},{\"title\":\"Our Values\",\"description\":\"Integrity, creativity, and user-centric design are at the core of our values, guiding us in every quiz we create.\"}],\"features\":[\"Wide range of quizzes\",\"Designed to be engaging\",\"prioritize user feedback\",\"24 X 7 Call & Chat Support\"],\"button\":{\"text\":\"Contact Us\",\"link\":\"\\/contact-us\"},\"phone_number\":\"+1 (123) 456-7890\"}'),(17,'Contact Us','ph ph-phone','contact-us','This is contact us section.','{\"title\":\"Let\\u2019s Get In Touch\",\"sub_title\":\"Contact Us\",\"list\":[{\"title\":\"Location\",\"description\":\"View on Google Maps\",\"icon\":\"ph ph-map-pin-line\",\"value\":\"https:\\/\\/maps.app.goo.gl\\/9k36Fz2NVrxDK9FfA\"},{\"title\":\"Email Address\",\"value\":\"quizix@example.com\",\"icon\":\"ph ph-envelope\"},{\"title\":\"Phone Number\",\"value\":\"+1 (123) 456-7890\",\"icon\":\"ph ph-phone\"}]}'),(18,'Contact Form','ph ph-phone','contact-form','This is contact us section.','{\"button_text\":\"Send Message\"}'),(19,'Trams and Conditions','ph ph-file-text','terms-and-conditions','This is a default section. That is dynamically generate for new page if the page is not us other sections','{\"content\":\"<div class=\\\"stp-30 custom-container flex flex-col gap-6\\\">\\n        <div class=\\\"flex flex-col gap-3\\\">\\n          <h3 class=\\\"heading-3\\\">General Terms<\\/h3>\\n          <p class=\\\"text-black\\/80\\\">\\n            By accessing and placing an order with QuiziX, you confirm that you\\n            are in agreement with and bound by the terms of service contained in\\n            the Terms & Conditions outlined below. These terms apply to the\\n            entire website and any email or other type of communication between\\n            you and QuiziX.\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            Under no circumstances shall QuiziX team be liable for any direct,\\n            indirect, special, incidental or consequential damages, including,\\n            but not limited to, loss of data or profit, arising out of the use,\\n            or the inability to use, the materials on this site, even if QuiziX\\n            team or an authorized representative has been advised of the\\n            possibility of such damages. If your use of materials from this site\\n            results in the need for servicing, repair or correction of equipment\\n            or data, you assume any costs thereof.\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            QuiziX will not be responsible for any outcome that may occur during\\n            the course of usage of our resources. We reserve the rights to\\n            change prices and revise the resources usage policy in any moment.\\n          <\\/p>\\n        <\\/div>\\n        <div class=\\\"flex flex-col gap-3\\\">\\n          <h3 class=\\\"heading-3\\\">License<\\/h3>\\n          <p class=\\\"text-black\\/80\\\">\\n            QuiziX grants you a revocable, non-exclusive, non-transferable,\\n            limited license to download, install and use the website strictly in\\n            accordance with the terms of this Agreement.\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            These Terms & Conditions are a contract between you and QuiziX\\n            (referred to in these Terms & Conditions as &quot;QuiziX&quot;,\\n            &quot;us&quot;, &quot;we&quot; or &quot;our&quot;), the provider of\\n            the QuiziX website and the services accessible from the QuiziX\\n            website (which are collectively referred to in these Terms &\\n            Conditions as the &quot;QuiziX Service&quot;).\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            You are agreeing to be bound by these Terms & Conditions. If you do\\n            not agree to these Terms & Conditions, please do not use the QuiziX\\n            Service. In these Terms & Conditions, &quot;you&quot; refers both to\\n            you as an individual and to the entity you represent. If you violate\\n            any of these Terms & Conditions, we reserve the right to cancel your\\n            account or block access to your account without notice.\\n          <\\/p>\\n        <\\/div>\\n        <div class=\\\"flex flex-col gap-3\\\">\\n          <h3 class=\\\"heading-3\\\">Return and Refund Policy<\\/h3>\\n          <p class=\\\"text-black\\/80\\\">\\n            Thanks for shopping at QuiziX. We appreciate the fact that you like\\n            to buy the stuff we build. We also want to make sure you have a\\n            rewarding experience while you\\u2019re exploring, evaluating, and\\n            purchasing our products.\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            As with any shopping experience, there are terms and conditions that\\n            apply to transactions at QuiziX. We\\u2019ll be as brief as our attorneys\\n            will allow. The main thing to remember is that by placing an order\\n            or making a purchase at QuiziX, you agree to the terms along with\\n            QuiziX&apos;s Privacy Policy.\\n          <\\/p>\\n          <p class=\\\"text-black\\/80\\\">\\n            If, for any reason, You are not completely satisfied with any good\\n            or service that we provide, don&apos;t hesitate to contact us and we\\n            will discuss any of the issues you are going through with our\\n            product.\\n          <\\/p>\\n        <\\/div>\\n        <div class=\\\"flex flex-col gap-3\\\">\\n          <h3 class=\\\"heading-3\\\">Your Consent<\\/h3>\\n          <p class=\\\"text-black\\/80\\\">\\n            We&apos;ve updated our Terms & Conditions to provide you with\\n            complete transparency into what is being set when you visit our site\\n            and how it&apos;s being used. By using our website, registering an\\n            account, or making a purchase, you hereby consent to our Terms &\\n            Conditions.\\n          <\\/p>\\n        <\\/div>\\n        <div class=\\\"flex flex-col gap-3\\\">\\n          <h3 class=\\\"heading-3\\\">Cookies<\\/h3>\\n          <p class=\\\"text-black\\/80\\\">\\n            QuiziX uses &quot;Cookies&quot; to identify the areas of our website\\n            that you have visited. A Cookie is a small piece of data stored on\\n            your computer or mobile device by your web browser. We use Cookies\\n            to enhance the performance and functionality of our website but are\\n            non-essential to their use. However, without these cookies, certain\\n            functionality like videos may become unavailable or you would be\\n            required to enter your login details every time you visit the\\n            website as we would not be able to remember that you had logged in\\n            previously. Most web browsers can be set to disable the use of\\n            Cookies. However, if you disable Cookies, you may not be able to\\n            access functionality on our website correctly or at all. We never\\n            place Personally Identifiable Information in Cookies.\\n          <\\/p>\\n        <\\/div>\\n      <\\/div>\"}'),(20,'Privacy Policy','ph ph-file-text','privacy-policy','This is a default section. That is dynamically generate for new page if the page is not us other sections','{\"content\":\"<div class=\\\"max-w-4xl mx-auto p-6 bg-white rounded-lg shadow-sm\\\">\\n            <h1 class=\\\"text-3xl font-bold text-gray-800 mb-6\\\">Privacy Policy<\\/h1>\\n            <p class=\\\"text-gray-700 mb-4\\\">Welcome to Botivus (\\\"Company,\\\" \\\"we,\\\" \\\"us,\\\" or \\\"our\\\"). Your privacy is important to us. This Privacy Policy explains how we collect, use, disclose, and protect your personal information when you use our yacht rental and sales platform (the \\\"Platform\\\"), accessible via Botivus.<\\/p>\\n            <p class=\\\"text-gray-700 mb-6\\\">By using our services, you agree to the collection and use of your information as described in this policy.<\\/p>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">1. Information We Collect<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">We may collect different types of personal information, including but not limited to:<\\/p>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">1.1 Personal Information Provided by Users<\\/h3>\\n                <ul class=\\\"list-disc ml-6 text-gray-700\\\">\\n                    <li><span class=\\\"font-medium\\\">Account Information:<\\/span> Name, email, phone number, password.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Profile Information:<\\/span> Profile picture, address, yacht preferences.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Transaction Details:<\\/span> Payment information, billing address.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Communication Data:<\\/span> Messages or support requests.<\\/li>\\n                <\\/ul>\\n                <\\/div>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">1.2 Information Collected Automatically<\\/h3>\\n                <ul class=\\\"list-disc ml-6 text-gray-700\\\">\\n                    <li><span class=\\\"font-medium\\\">Device Information:<\\/span> IP address, browser type, operating system.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Usage Data:<\\/span> Pages visited, time spent on the platform, clicks, and interactions.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Location Data:<\\/span> If enabled, we may collect your approximate location.<\\/li>\\n                <\\/ul>\\n                <\\/div>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">1.3 Information from Third Parties<\\/h3>\\n                <ul class=\\\"list-disc ml-6 text-gray-700\\\">\\n                    <li><span class=\\\"font-medium\\\">Payment Providers:<\\/span> Transaction status and details.<\\/li>\\n                    <li><span class=\\\"font-medium\\\">Social Media Login:<\\/span> If you sign up using Google, Facebook, or Apple, we may receive basic profile data.<\\/li>\\n                <\\/ul>\\n                <\\/div>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">2. How We Use Your Information<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">We use your information to:<\\/p>\\n                <ul class=\\\"ml-6 text-gray-700\\\">\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Provide and improve our services (e.g., yacht rentals, purchases, user profiles).<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Process payments and transactions securely.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Enable communication between buyers, renters, and sellers.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Personalize user experience and offer recommendations.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Send important updates (e.g., booking confirmations, policy changes).<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Prevent fraud, unauthorized access, or illegal activities.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Comply with legal obligations and enforce our terms.<\\/li>\\n                <\\/ul>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">3. Sharing & Disclosure of Information<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">We do not sell your personal data. However, we may share it under the following conditions:<\\/p>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">3.1 With Other Users<\\/h3>\\n                <p class=\\\"text-gray-700\\\">Sellers receive buyer\\/renter details (e.g., name, contact information) to facilitate transactions.<\\/p>\\n                <\\/div>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">3.2 With Third-Party Service Providers<\\/h3>\\n                <p class=\\\"text-gray-700 mb-2\\\">We may share data with:<\\/p>\\n                <ul class=\\\"list-disc ml-6 text-gray-700\\\">\\n                    <li>Payment processors (e.g., Stripe, PayPal, Remitly) for secure transactions.<\\/li>\\n                    <li>Cloud storage and analytics providers to improve our services.<\\/li>\\n                    <li>Marketing & communication tools for email notifications.<\\/li>\\n                <\\/ul>\\n                <\\/div>\\n\\n                <div class=\\\"ml-4 mb-4\\\">\\n                <h3 class=\\\"text-xl font-medium text-gray-800 mb-2\\\">3.3 Legal Compliance & Security<\\/h3>\\n                <p class=\\\"text-gray-700\\\">We may disclose information when required by law, to enforce our policies, or protect against fraud or security threats.<\\/p>\\n                <\\/div>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">4. Data Retention & Security<\\/h2>\\n                <ul class=\\\"list-disc ml-6 text-gray-700\\\">\\n                <li>We retain your data only as long as necessary for business or legal reasons.<\\/li>\\n                <li>We implement encryption, firewalls, and access controls to protect your data.<\\/li>\\n                <li>However, no online platform is 100% secure, so users should take precautions.<\\/li>\\n                <\\/ul>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">5. Your Rights & Choices<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">Depending on your location, you may have rights over your data, such as:<\\/p>\\n                <ul class=\\\"ml-6 text-gray-700\\\">\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Access: Request a copy of your personal data.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Correction: Update inaccurate or incomplete information.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Deletion: Request to delete your account and associated data.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Opt-out: Unsubscribe from marketing emails.<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"text-green-500 mr-2\\\">\\u2714<\\/span> Restrict Processing: Limit how we use your data.<\\/li>\\n                <\\/ul>\\n                <p class=\\\"text-gray-700 mt-3\\\">To exercise these rights, contact us at info@botivus.com.<\\/p>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">6. Cookies & Tracking Technologies<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">We use cookies and similar technologies to:<\\/p>\\n                <ul class=\\\"ml-6 text-gray-700\\\">\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"mr-2\\\">\\ud83c\\udf6a<\\/span> Improve website functionality<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"mr-2\\\">\\ud83d\\udcca<\\/span> Analyze user behavior<\\/li>\\n                <li class=\\\"flex items-start mb-2\\\"><span class=\\\"mr-2\\\">\\ud83d\\udce2<\\/span> Show relevant ads (if applicable)<\\/li>\\n                <\\/ul>\\n                <p class=\\\"text-gray-700 mt-3\\\">You can manage cookie preferences through your browser settings.<\\/p>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">7. Third-Party Links & Services<\\/h2>\\n                <p class=\\\"text-gray-700\\\">Our platform may contain links to third-party websites. We are not responsible for their privacy practices. We encourage you to read their policies before providing personal information.<\\/p>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">8. Children Privacy<\\/h2>\\n                <p class=\\\"text-gray-700\\\">Our services are not intended for children under 13 (or applicable age per local law). If we discover a child has provided personal data, we will delete it.<\\/p>\\n            <\\/div>\\n\\n            <div class=\\\"mb-8\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">9. Changes to This Policy<\\/h2>\\n                <p class=\\\"text-gray-700\\\">We may update this Privacy Policy periodically. We will notify users of significant changes via email or platform notifications.<\\/p>\\n            <\\/div>\\n\\n            <div class=\\\"mb-4\\\">\\n                <h2 class=\\\"text-2xl font-semibold text-gray-800 mb-4\\\">10. Contact Us<\\/h2>\\n                <p class=\\\"text-gray-700 mb-3\\\">If you have any questions or concerns about this Privacy Policy, please contact us at:<\\/p>\\n                <div class=\\\"bg-gray-50 p-4 rounded-lg\\\">\\n                <p class=\\\"text-gray-700\\\"><span class=\\\"mr-2\\\">\\ud83d\\udce7<\\/span> Email: info@botivus.com<\\/p>\\n                <p class=\\\"text-gray-700\\\"><span class=\\\"mr-2\\\">\\ud83d\\udccd<\\/span> Address: Dhaka, Bangladesh<\\/p>\\n                <\\/div>\\n            <\\/div>\\n            <\\/div>\"}'),(21,'Confidentiality & Privacy','ph ph-campfire','confidentiality-and-privacy','Confidentiality & Privacy Policy','{\"content\":\"<section class=\\\"max-w-4xl mx-auto p-6 bg-white rounded-lg shadow-sm\\\">\\n                    <h2 class=\\\"text-2xl font-bold mb-4\\\">Confidentiality & Privacy<\\/h2>\\n\\n                    <p class=\\\"mb-4\\\">\\n                        At our Yacht Rental and Sales platform, we are fully committed to safeguarding the privacy and confidentiality of our users. This policy outlines how we collect, use, and protect your personal data.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Information Collection<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        We collect personal information when you register, book a yacht, make a payment, or communicate with us. This may include your name, contact details, identification documents, and payment information.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Use of Information<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        The information we collect is used solely to provide and improve our services, facilitate yacht bookings and purchases, process transactions, communicate with users, and ensure compliance with local regulations.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Data Protection<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        We use industry-standard security measures to protect your personal data. All sensitive information is encrypted and securely stored. Access to your data is restricted to authorized personnel only.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Third-Party Disclosure<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        We do not sell, trade, or otherwise transfer your personal information to outside parties, except when necessary to complete a transaction (e.g., payment gateways) or when required by law.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Your Rights<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        You have the right to access, update, or delete your personal information at any time. Please contact us if you wish to exercise these rights.\\n                    <\\/p>\\n\\n                    <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Policy Updates<\\/h3>\\n                    <p class=\\\"mb-4\\\">\\n                        This Confidentiality & Privacy Policy may be updated from time to time. We encourage users to review this section periodically to stay informed about how we protect your data.\\n                    <\\/p>\\n\\n                    <p class=\\\"mt-6\\\">\\n                        If you have any questions or concerns regarding our privacy practices, please feel free to contact our support team.\\n                    <\\/p>\\n                <\\/section>\\n                \"}'),(22,'Legal Information','ph ph-gavel','legal-information','Legal Information','{\"content\":\"<section class=\\\"max-w-4xl mx-auto p-6 bg-white rounded-lg shadow-sm\\\">\\n                        <h2 class=\\\"text-2xl font-bold mb-4\\\">Legal Information<\\/h2>\\n\\n                        <p class=\\\"mb-4\\\">\\n                            This Legal Information section outlines the terms and conditions under which our yacht rental and sales platform operates. By using our website or services, you agree to comply with all applicable laws and the terms outlined below.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Ownership & Intellectual Property<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            All content on this website, including text, images, logos, graphics, and software, is the property of our platform or its content suppliers and is protected by copyright, trademark, and other intellectual property laws. Unauthorized use, reproduction, or distribution of any content is strictly prohibited.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Use of Services<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            Our platform provides a marketplace for users to list, rent, and purchase yachts. By accessing or using our services, you agree not to misuse the platform or engage in any fraudulent or illegal activity.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Limitation of Liability<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            We are not liable for any direct, indirect, incidental, or consequential damages arising from the use of our platform, including but not limited to loss of profits, data, or reputation. Users agree to use the platform at their own risk.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Third-Party Services<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            We may integrate third-party services such as payment gateways, map services, or messaging tools. We are not responsible for the terms, performance, or security of these third-party services.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Jurisdiction & Governing Law<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            This platform is governed by the laws of the jurisdiction in which the company is registered. Any disputes arising from the use of this website shall be subject to the exclusive jurisdiction of the local courts.\\n                        <\\/p>\\n\\n                        <h3 class=\\\"text-xl font-semibold mt-6 mb-2\\\">Policy Changes<\\/h3>\\n                        <p class=\\\"mb-4\\\">\\n                            We reserve the right to modify this legal information at any time. Changes will be effective immediately upon posting. Users are encouraged to review this page regularly for updates.\\n                        <\\/p>\\n\\n                        <p class=\\\"mt-6\\\">\\n                            For legal inquiries or additional information, please contact our legal department or customer support.\\n                        <\\/p>\\n                    <\\/section>\"}');
