okies or any other tracking technologies when you visit our website, including any other media form, mobile website, or mobile application related or connected to help customize the Site and improve your experience.\"}',NULL,NULL),(4,'badge_criteria','[\"high_score_quizzes\",\"perfect_consecutive\",\"fast_completion_accuracy\",\"leaderboard_rank\",\"quizzes_attempted\",\"consecutive_days\",\"quizzes_completed\"]',NULL,NULL),(5,'company_info','{\"company_info\":{\"name\":\"Quizix\",\"email\":\"support@quizix.com\",\"phone\":\"+123 456 789\",\"website\":\"www.quizix.com\"},\"address\":{\"country\":\"United States\",\"state\":\"California\",\"city\":\"Los Angeles\",\"postal_code\":\"90001\",\"address\":\"1600 Amphitheatre Parkway, Mountain View, CA 94044\",\"location\":\"https:\\/\\/maps.app.goo.gl\\/GZ9YQZa2v15d1LhY7\"},\"timezone\":\"UTC\",\"frontend_url\":\"http:\\/\\/localhost:3000\",\"otp\":{\"expire_time\":\"1\",\"digit_range\":[\"10000\",\"99999\"]},\"theme\":{\"primary_color\":\"#008744\",\"secondary_color\":\"#ffa700\"},\"referral\":{\"joining\":\"100\"},\"footer_text\":\"All rights reserved.\",\"auth_left_sidebar_image\":\"\\/assets\\/client\\/sign-in-img.webp\"}',NULL,NULL);
