DROP TABLE IF EXISTS `questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `questions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `question_category_id` bigint unsigned NOT NULL,
  `explanation_type` enum('text','video','image','audio','none') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text',
  `time_limit` int unsigned NOT NULL DEFAULT '0',
  `score` int unsigned NOT NULL DEFAULT '1',
  `is_display_split_tab` tinyint(1) NOT NULL DEFAULT '1',
  `question_type` enum('multiple_choice','single_choice','true_false','fill_in_the_blank','multiple_dropdown','draggable_rearrange','multi_column_single_choice','multi_column_multi_choice','drag_drop_matching') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'multiple_choice',
  `question_input_type` enum('text','multi_tab_based','single_tab_based','video','image','audio') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text',
  `options` longtext COLLATE utf8mb4_unicode_ci,
  `correct_answers` longtext COLLATE utf8mb4_unicode_ci,
  `status` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `questions_question_category_id_foreign` (`question_category_id`),
  CONSTRAINT `questions_question_category_id_foreign` FOREIGN KEY (`question_category_id`) REFERENCES `question_categories` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
