LOCK TABLES `quiz_translations` WRITE;
/*!40000 ALTER TABLE `quiz_translations` DISABLE KEYS */;
INSERT INTO `quiz_translations` VALUES (1,1,'en','World Capitals',NULL,'world-capitals-','Test your knowledge of world capitals with this comprehensive quiz.\n    Challenge yourself to identify the capital cities of every country across the continents.\n    Learn interesting facts about each city, including its culture, geography, and historical significance.\n    This quiz is perfect for travelers, geography enthusiasts, and students wanting to improve their global awareness.\n    Each question will help you remember not just the names, but also unique aspects of these cities.'),(2,2,'en','Famous Personalities',NULL,'famous-personalities-','Identify important figures from history and modern times in this engaging quiz.\n    From legendary leaders and revolutionaries to influential artists, scientists, and innovators, this quiz covers a wide range of personalities.\n    Learn about their contributions, achievements, and the impact they had on the world.\n    Enhance your understanding of historical timelines and cultural milestones.\n    This quiz is designed to both test and expand your knowledge of remarkable individuals.'),(3,3,'en','Inventions & Discoveries',NULL,'inventions-discoveries-','Dive into the fascinating world of inventions and discoveries with this quiz.\n    Explore groundbreaking innovations that have changed the course of history.\n    Learn about the brilliant minds behind these inventions and the challenges they overcame.\n    Understand how these discoveries shaped science, technology, and everyday life.\n    This quiz will test your knowledge and also give you insight into the stories behind major breakthroughs.'),(4,4,'en','Current Affairs',NULL,'current-affairs-','Check your awareness about recent events happening around the world with this quiz.\n    Stay updated on global news, politics, science, sports, and cultural happenings.\n    Each question challenges you to remember important developments and their implications.\n    Enhance your understanding of how current events influence societies and economies.\n    This quiz is ideal for anyone wanting to stay informed and knowledgeable about the modern world.'),(5,5,'en','Mixed General Knowledge',NULL,'mixed-general-knowledge-','A fun and challenging quiz that covers a variety of topics from different fields.\n    Test your memory and knowledge on history, science, literature, sports, geography, and more.\n    Each question is designed to keep you thinking and learning something new.\n    Improve your overall general knowledge while enjoying an unpredictable mix of questions.\n    Perfect for quizzes, competitions, or simply challenging yourself with random trivia.'),(6,6,'en','Physics Basics',NULL,'physics-basics-','Explore the fundamental concepts of physics in this quiz.\n    Learn about motion, forces, energy, and the laws that govern the universe.\n    Understand how objects interact, the principles of mechanics, and the basics of thermodynamics.\n    This quiz also introduces concepts like electricity, magnetism, and waves in a simple manner.\n    Perfect for students, enthusiasts, or anyone curious about how the physical world works.\n    Challenge yourself and strengthen your foundation in physics with every question.'),(7,7,'en','Chemistry Essentials',NULL,'chemistry-essentials-','Dive into the fascinating world of chemistry with this quiz.\n    Understand atoms, molecules, chemical reactions, and the periodic table.\n    Learn about acids, bases, compounds, and the properties of elements.\n    Explore the science behind everyday substances and materials around you.\n    This quiz is ideal for students, budding chemists, or anyone interested in how matter behaves.\n    Test your knowledge and discover the chemistry that shapes our world.'),(8,8,'en','Biology Facts',NULL,'biology-facts-','Test your knowledge about living organisms with this engaging biology quiz.\n    Explore topics like cells, genetics, ecosystems, and human anatomy.\n    Learn about the diversity of life, evolutionary processes, and the interconnection of species.\n    Understand how organisms survive, reproduce, and adapt to their environments.\n    Perfect for students, nature enthusiasts, or anyone curious about life sciences.\n    Each question is designed to strengthen your understanding of the living world.'),(9,9,'en','Space & Astronomy',NULL,'space-astronomy-','Journey into the cosmos with this exciting space and astronomy quiz.\n    Learn about planets, stars, galaxies, black holes, and the vast universe beyond Earth.\n    Discover the science of celestial phenomena and the history of space exploration.\n    Explore topics like the solar system, constellations, and the mysteries of dark matter.\n    Ideal for astronomy enthusiasts, students, or anyone fascinated by outer space.\n    Each question will expand your knowledge about the wonders of the universe.'),(10,10,'en','Earth Science',NULL,'earth-science-','Explore the dynamic systems of our planet with this Earth science quiz.\n    Learn about geology, weather, oceans, climate, and natural phenomena like earthquakes and volcanoes.\n    Understand how Earth’s layers, rocks, and minerals interact to shape the planet’s surface.\n    Discover the science behind environmental processes, ecosystems, and natural resources.\n    Perfect for students, environmental enthusiasts, or anyone curious about our planet.\n    Each question provides insights into the forces and processes that sustain life on Earth.'),(11,11,'en','Ancient Civilizations',NULL,'ancient-civilizations-','Explore the fascinating world of early human civilizations in this quiz.\n    Learn about Mesopotamia, Egypt, the Indus Valley, China, and Mesoamerica.\n    Discover how these societies developed agriculture, writing, trade, and governance.\n    Understand the cultural, technological, and architectural achievements that shaped human history.\n    Perfect for history enthusiasts, students, or anyone curious about t